/**
 * Low-level Web Crypto API wrappers.
 * No business logic here — only raw cryptographic primitives.
 */

import type { KeyPair } from "./types"

// -------------------------
// Encoding helpers
// -------------------------

/** Encode an ArrayBuffer to a base64 string. */
export function toBase64(buf: ArrayBuffer): string {
    return btoa(String.fromCharCode(...new Uint8Array(buf)))
}

/** Decode a base64 string back to an ArrayBuffer. */
export function fromBase64(b64: string): ArrayBuffer {
    return Uint8Array.from(atob(b64), c => c.charCodeAt(0)).buffer
}

// -------------------------
// ECDH P-256
// -------------------------

/**
 * Generate a non-extractable ECDH P-256 key pair.
 * Private key is marked non-extractable so raw bytes never leave WebCrypto.
 */
export async function generateKeyPair(): Promise<KeyPair> {
    return crypto.subtle.generateKey(
        { name: "ECDH", namedCurve: "P-256" },
        false,
        ["deriveKey", "deriveBits"]
    ) as Promise<KeyPair>
}

/** Export a public key as a base64-encoded raw (uncompressed) point. */
export async function exportPublicKey(key: CryptoKey): Promise<string> {
    const raw = await crypto.subtle.exportKey("raw", key)
    return toBase64(raw)
}

/** Import a base64-encoded raw public key for use in ECDH. */
export async function importPublicKey(b64: string): Promise<CryptoKey> {
    return crypto.subtle.importKey(
        "raw",
        fromBase64(b64),
        { name: "ECDH", namedCurve: "P-256" },
        true,
        []
    )
}

/** Compute a 256-bit ECDH shared secret from a private key and a peer's public key. */
export async function deriveBits(privateKey: CryptoKey, publicKey: CryptoKey): Promise<ArrayBuffer> {
    return crypto.subtle.deriveBits(
        { name: "ECDH", public: publicKey },
        privateKey,
        256
    )
}

// -------------------------
// HKDF-SHA-256
// -------------------------

/**
 * Derive `length` bytes from `inputKey` using HKDF-SHA-256.
 * @param length Output length in bytes (default 32).
 */
export async function hkdf(
    inputKey: ArrayBuffer,
    salt: ArrayBuffer,
    info: string,
    length: number = 32
): Promise<ArrayBuffer> {
    const key = await crypto.subtle.importKey(
        "raw", inputKey, "HKDF", false, ["deriveBits"]
    )
    return crypto.subtle.deriveBits(
        {
            name: "HKDF",
            hash: "SHA-256",
            salt,
            info: new TextEncoder().encode(info)
        },
        key,
        length * 8
    )
}

/**
 * Derive two 32-byte keys from one input (64 bytes of HKDF output, split in half).
 * Used for the Double Ratchet root-key step: new root key + new chain key.
 */
export async function hkdfExpand(
    inputKey: ArrayBuffer,
    salt: ArrayBuffer,
    info: string
): Promise<{ key1: ArrayBuffer, key2: ArrayBuffer }> {
    const output = await hkdf(inputKey, salt, info, 64)
    return {
        key1: output.slice(0, 32),
        key2: output.slice(32, 64)
    }
}

// -------------------------
// AES-256-GCM
// -------------------------

/** Import raw bytes as an AES-256-GCM CryptoKey. */
export async function importAESKey(raw: ArrayBuffer): Promise<CryptoKey> {
    return crypto.subtle.importKey(
        "raw", raw, { name: "AES-GCM", length: 256 }, false, ["encrypt", "decrypt"]
    )
}

/**
 * Encrypt a UTF-8 string with AES-256-GCM using a fresh random 96-bit IV.
 * @returns Base64-encoded IV and ciphertext (includes GCM auth tag).
 */
export async function aesEncrypt(
    keyBytes: ArrayBuffer,
    plaintext: string
): Promise<{ iv: string, ciphertext: string }> {
    const iv = crypto.getRandomValues(new Uint8Array(12))
    const key = await importAESKey(keyBytes)
    const encoded = new TextEncoder().encode(plaintext)
    const ciphertext = await crypto.subtle.encrypt(
        { name: "AES-GCM", iv },
        key,
        encoded
    )
    return {
        iv: toBase64(iv.buffer),
        ciphertext: toBase64(ciphertext)
    }
}

/**
 * Decrypt AES-256-GCM ciphertext.
 * Throws `OperationError` if authentication tag is invalid (tampered data or wrong key).
 */
export async function aesDecrypt(
    keyBytes: ArrayBuffer,
    iv: string,
    ciphertext: string
): Promise<string> {
    const key = await importAESKey(keyBytes)
    const decrypted = await crypto.subtle.decrypt(
        { name: "AES-GCM", iv: fromBase64(iv) },
        key,
        fromBase64(ciphertext)
    )
    return new TextDecoder().decode(decrypted)
}

// -------------------------
// SHA-256
// -------------------------

/** Compute SHA-256 of an ArrayBuffer. */
export async function sha256(data: ArrayBuffer): Promise<ArrayBuffer> {
    return crypto.subtle.digest("SHA-256", data)
}

// -------------------------
// ECDSA P-256 (signing)
// -------------------------

/**
 * Generate a non-extractable ECDSA P-256 signing key pair.
 * Public key is extractable so we can publish it; private stays in WebCrypto.
 */
export async function generateSigningKeyPair(): Promise<KeyPair> {
    return crypto.subtle.generateKey(
        { name: "ECDSA", namedCurve: "P-256" },
        false,
        ["sign", "verify"]
    ) as Promise<KeyPair>
}

/** Export an ECDSA public key as base64 SPKI (DER). */
export async function exportSigningPublicKey(key: CryptoKey): Promise<string> {
    const spki = await crypto.subtle.exportKey("spki", key)
    return toBase64(spki)
}

/** Import a base64 SPKI ECDSA public key for verification. */
export async function importSigningPublicKey(b64: string): Promise<CryptoKey> {
    return crypto.subtle.importKey(
        "spki",
        fromBase64(b64),
        { name: "ECDSA", namedCurve: "P-256" },
        true,
        ["verify"]
    )
}

/** Sign a message with ECDSA P-256 + SHA-256. Returns base64 signature (raw r||s). */
export async function ecdsaSign(privateKey: CryptoKey, message: ArrayBuffer): Promise<string> {
    const sig = await crypto.subtle.sign(
        { name: "ECDSA", hash: "SHA-256" },
        privateKey,
        message
    )
    return toBase64(sig)
}

/** Verify an ECDSA P-256 + SHA-256 signature. */
export async function ecdsaVerify(
    publicKey: CryptoKey,
    signatureB64: string,
    message: ArrayBuffer
): Promise<boolean> {
    return crypto.subtle.verify(
        { name: "ECDSA", hash: "SHA-256" },
        publicKey,
        fromBase64(signatureB64),
        message
    )
}
